import React, { useEffect, useState } from 'react';
import Modal from '../components/Modal';
import {
  getFoods, addFood, deleteFood,
  getRooms, addRoom, deleteRoom,
  getBookings, getUsers
} from '../services/adminApi';

const Admin = () => {
  const [tab, setTab] = useState('dashboard');
  const [foods, setFoods] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [users, setUsers] = useState([]);

  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState({ name: '', price: '' });

  // LOAD DATA
  const load = async () => {
    const f = await getFoods();
    const r = await getRooms();
    const b = await getBookings();
    const u = await getUsers();

    setFoods(f.data);
    setRooms(r.data);
    setBookings(b.data.room_bookings);
    setUsers(u.data);
  };

  useEffect(() => { load(); }, []);

  // ADD FOOD
  const handleAddFood = async () => {
    await addFood(form);
    setModalOpen(false);
    load();
  };

  return (
    <div className="admin">

      {/* SIDEBAR */}
      <div className="sidebar">
        <h2>Admin</h2>
        <button onClick={() => setTab('dashboard')}>Dashboard</button>
        <button onClick={() => setTab('foods')}>Food</button>
        <button onClick={() => setTab('rooms')}>Rooms</button>
        <button onClick={() => setTab('bookings')}>Bookings</button>
        <button onClick={() => setTab('users')}>Users</button>
      </div>

      {/* MAIN */}
      <div className="main">

        {tab === 'dashboard' && (
          <div className="grid">
            <div className="card">Foods: {foods.length}</div>
            <div className="card">Rooms: {rooms.length}</div>
            <div className="card">Bookings: {bookings.length}</div>
            <div className="card">Users: {users.length}</div>
          </div>
        )}

        {tab === 'foods' && (
          <>
            <h2>Food Management</h2>
            <button onClick={() => setModalOpen(true)}>+ Add Food</button>

            {foods.map(f => (
              <div className="row" key={f.id}>
                {f.name} - {f.price}
                <button onClick={() => deleteFood(f.id).then(load)}>Delete</button>
              </div>
            ))}
          </>
        )}

        {tab === 'rooms' && (
          <>
            <h2>Room Management</h2>
            <button onClick={() => addRoom({ name:"Room", price:5000 }).then(load)}>+ Add</button>

            {rooms.map(r => (
              <div className="row" key={r.id}>
                {r.name} - {r.price}
                <button onClick={() => deleteRoom(r.id).then(load)}>Delete</button>
              </div>
            ))}
          </>
        )}

        {tab === 'bookings' && (
          bookings.map(b => (
            <div className="row" key={b.id}>
              {b.room_name} | {b.check_in}
            </div>
          ))
        )}

        {tab === 'users' && (
          users.map(u => (
            <div className="row" key={u.user_id}>
              {u.username} | {u.email}
            </div>
          ))
        )}

      </div>

      {/* MODAL */}
      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)}>
        <h3>Add Food</h3>
        <input placeholder="Name" onChange={e => setForm({...form, name:e.target.value})}/>
        <input placeholder="Price" onChange={e => setForm({...form, price:e.target.value})}/>
        <button onClick={handleAddFood}>Save</button>
      </Modal>

      {/* STYLES */}
      <style>{`
        .admin { display:flex; height:100vh; }
        .sidebar { width:220px; background:#111; color:white; padding:20px; }
        .sidebar button { display:block; margin:10px 0; width:100%; }
        .main { flex:1; padding:20px; overflow:auto; }
        .grid { display:grid; grid-template-columns:repeat(4,1fr); gap:20px; }
        .card { background:#eee; padding:20px; border-radius:10px; }
        .row { background:#fafafa; margin:10px 0; padding:10px; display:flex; justify-content:space-between; }
      `}</style>

    </div>
  );
};

export default Admin;
